UPDATE public.garden_import_queue SET payload = '{"species": "Cranberry", "species_slug": "cranberry", "varieties": [{"name": "Roselle / Florida Cranberry (Hibiscus sabdariffa) 🌱", "slug": "roselle-florida-cranberry-hibiscus-sabdariffa", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "origin": "Central/West Africa, widely naturalized in tropics/subtropics worldwide", "traits": "Shrubby annual/perennial (4-8 feet tall), lobed dark green leaves, yellow flowers with red center, edible red calyces", "flesh_fruit": "Bright red fleshy calyces (seed pods), tart cranberry-like flavor, rich in vitamin C, antioxidants, anthocyanins", "yield_notes": "Abundant calyx production October-December, multiple harvests possible", "growing_notes": "PERFECT FOR BRISBANE SUBTROPICAL CLIMATE. Plant April-May after frost. Thrives in heat/humidity. Calyces used exactly like cranberries - sauces, jams, teas, juice, fresh cooking. Called ''Florida Cranberry'' due to color/flavor similarity. Traditional Caribbean Christmas drink (Sorrel). Also called Rosella, Jamaica Sorrel, Red Sorrel, Indian Sorrel. Leaves also edible (tangy, like spinach). Frost-sensitive. Blooms October, fruits November-December. Non-GMO.", "availability": "Readily available Brisbane garden centers, online Australian seed suppliers, subtropical nurseries", "sort_order": 0}, {"name": "Hibiscus sabdariffa ''Victor''", "slug": "hibiscus-sabdariffa-victor", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Selected variety, proven for hot climates", "traits": "Variety specifically selected for South Florida/subtropical performance", "flesh_fruit": "", "yield_notes": "", "growing_notes": "Recommended for Queensland climate. Superior performance in Brisbane conditions. Available from tropical/subtropical specialty nurseries.", "availability": "Specialty subtropical nurseries, rare seeds Australia", "sort_order": 1}, {"name": "Cranberry Hibiscus (Hibiscus acetosella)", "slug": 