UPDATE public.garden_import_queue SET payload = '{"species": "Curry Leaf", "species_slug": "curry-leaf", "varieties": [{"name": "Regular Type (Standard)", "slug": "regular-type-standard", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Native to Indian subcontinent, widely distributed", "traits": "Fast-growing, tall tree form (4-6m). Dark green compound leaves with 11-21 leaflets per stem, standard size (2-4cm per leaflet). Strong aromatic curry-like fragrance.", "flesh_fruit": "", "yield_notes": "High productivity, 100kg leaves per year from mature tree. Commercial harvest possible from 3-year-old plants.", "growing_notes": "", "availability": "Widely available at Queensland nurseries including Daleys Fruit Tree Nursery, Fruitopia Nursery (Brisbane/Gold Coast), The Heritage Nursery, Garden Express, Mudbrick Herb Cottage, Diggers Club. Most common type sold commercially.", "sort_order": 0}, {"name": "Dwarf Type (Compact)", "slug": "dwarf-type-compact", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Selected variety from Indian cultivation", "traits": "Compact shrub form, moderate growth rate, spreading branching habit (10-12 inches height at maturity). Bushier appearance than regular type. Light green foliage.", "flesh_fruit": "", "yield_notes": "Moderate yield, suitable for container cultivation and small gardens.", "growing_notes": "", "availability": "Available at specialty nurseries in Queensland. Check with Brisbane herb suppliers and online nurseries. Less common than regular type but increasingly available.", "sort_order": 1}, {"name": "Gamthi Type (Brown/Miniature) 🏆", "slug": "gamthi-type-brown-miniature", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Native variety from Gujarat, India, traditional heirloom", "traits": "Slow-growing miniature variety (1-3ft mature height). Thick, glossy, small leaves with serrated edges, dark brown-green coloration. Dense, bushy growth habit. Most compact of all types.", "flesh_fruit": "", "yield_notes": "Lower yield due to small size, but superior quality and aroma. Maximum 2-3 years to reach harvestable size. Ideal for continuous small harvests.", "growing_notes": "", "availability": "Rare in Australia. Occasionally available from specialist nurseries. Seeds of India (international) offers ''Prasad Family Gamthi'' strain in limited quantities. Worth seeking out for superior aroma and container suitability.", "sort_order": 2}, {"name": "Gomati/Gomatic Type (Dwarf Aromatic)", "slug": "gomati-gomatic-type-dwarf-aromatic", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Indian selection, similar to dwarf type", "traits": "Short, bushy plant with abundant foliage. Compact growth ideal for apartments/flats. More productive than standard dwarf with plenty of leaves.", "flesh_fruit": "", "yield_notes": "High yield relative to plant size. Low maintenance, high productivity. Perfect for regular harvesting.", "growing_notes": "", "availability": "Available from UK and European suppliers who may ship to Australia (check import regulations). Specialty online herb nurseries may stock.", "sort_order": 3}, {"name": "Indonesian Variety", "slug": "indonesian-variety", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Southeast Asian selection, adapted to tropical conditions", "traits": "Fastest growing of all curry leaf varieties. Vigorous growth, can become weedy if not controlled. More tropical adaptation.", "flesh_fruit": "", "yield_notes": "Very high productivity, prolific leaf production. Best for bulk leaf production rather than premium aroma.", "growing_notes": "", "availability": "May be found at Queensland nurseries specializing in Southeast Asian herbs. Check with Brisbane''s multicultural plant suppliers.", "sort_order": 4}, {"name": "Regular Type (Kariveppilai) 🌱", "slug": "regular-type-kariveppilai", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Native to Kerala and Indian subcontinent, indigenous to region, centuries of cultivation", "traits": "Fast-growing tree reaching 5-6m in Kerala''s tropical conditions. Dark green pinnate leaves, 11-21 leaflets per compound leaf. White fragrant flowers, black berries when ripe.", "flesh_fruit": "", "yield_notes": "Very high productivity in Kerala''s tropical monsoon climate. Mature trees yield 100kg+ leaves annually. Harvest every 2.5-3 months. Commercial production from 3-year plants.", "growing_notes": "", "availability": "Universally available throughout Kerala. Grown in home gardens, sold in local markets. Available from root suckers shared within community during monsoon season. Kerala agriculture nurseries, spice nurseries in Thiruvalla region.", "sort_order": 0}, {"name": "Gamthi Type (Brown/Gujarati) 🏆", "slug": "gamthi-type-brown-gujarati", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "", "sort_order": 1}, {"name": "DWD-1 (Dharwad-1)", "slug": "dwd-1-dharwad-1", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Developed by University of Agricultural Sciences, Dharwad, Karnataka. Released as commercial variety.", "traits": "Improved cultivar selected from Western Ghats germplasm. Good growth vigor, genetically distinct from local landraces.", "flesh_fruit": "", "yield_notes": "Good commercial yields suitable for plantation scale cultivation.", "growing_notes": "", "availability": "Available through Karnataka agricultural nurseries. May be obtainable through Kerala agricultural universities and government spice nurseries. Check with Kerala Horticultural Development Programme.", "sort_order": 2}, {"name": "DWD-2 (Dharwad-2 / Suwasini / Suhasini)", "slug": "dwd-2-dharwad-2-suwasini-suhasini", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Developed by University of Agricultural Sciences, Dharwad, Karnataka. Released as improved commercial variety.", "traits": "Improved cultivar with winter tolerance. Genetically distinct from DWD-1. Insensitive to low temperatures - maintains growth during cooler months.", "flesh_fruit": "", "yield_notes": "Higher yield than DWD-1 due to cold tolerance allowing year-round production. Excellent commercial productivity.", "growing_notes": "", "availability": "Available through Karnataka and Kerala agricultural nurseries. VNR Nursery Karnataka. Kerala state agriculture departments, spice development boards.", "sort_order": 3}, {"name": "Senkaampu (Sen Kaampa) 🏆 🌱", "slug": "senkaampu-sen-kaampa", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "", "sort_order": 4}, {"name": "Krishna Variety 🌱", "slug": "krishna-variety", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Indian regional variety", "traits": "Distinguished by dark blackish-green leaves - unique coloration from regular variety. Cultivated for distinctive appearance.", "flesh_fruit": "", "yield_notes": "Good productivity, ornamental value due to distinctive leaf color.", "growing_notes": "", "availability": "Rare variety. May be available from Indian specialty nurseries or agricultural research stations.", "sort_order": 5}, {"name": "Palani Variety 🏆 🌱", "slug": "palani-variety", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Native to Palani Hills, Tamil Nadu (Western Ghats region bordering Kerala)", "traits": "Hill variety adapted to Western Ghats conditions. Regional selection from elevated areas.", "flesh_fruit": "", "yield_notes": "Moderate yield, superior quality due to hill cultivation.", "growing_notes": "", "availability": "Rare. May be found in Palani Hills area nurseries, Western Ghats agricultural stati