al shipping", "sort_order": 5}, {"name": "7. Watermelon Radish", "slug": "7-watermelon-radish", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "China (heirloom)", "traits": "Round 5-10cm, green/white exterior, pink interior", "flesh_fruit": "Crisp, sweet, spicy, pink", "yield_notes": "Moderate, 30-80 days", "growing_notes": "", "availability": "Specialty seed importers, international heirloom companies", "sort_order": 6}, {"name": "8. China Rose Winter Radish", "slug": "8-china-rose-winter-radish", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "China (1548 documentation, 1845 introduction to West)", "traits": "Rose-pink elongated roots 10-15cm", "flesh_fruit": "White, crisp, firm, slightly spicy", "yield_notes": "Good, 25-55 days", "growing_notes": "", "availability": "Heirloom seed companies, international suppliers", "sort_order": 7}, {"name": "9. Korean Radish (Mu)", "slug": "9-korean-radish-mu", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Korea (traditional)", "traits": "Short stout, 15-20cm, white with green shoulders", "flesh_fruit": "Dense, crisp, peppery, sweet", "yield_notes": "Good", "growing_notes": "", "availability": "Korean specialty suppliers, limited in India", "sort_order": 8}, {"name": "10. Tokinashi All-Season", "slug": "10-tokinashi-all-season", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Japan (traditional Fukuoka variety)", "traits": "Long white roots 38-45cm, firm", "flesh_fruit": "White, crisp, strong pungency", "yield_notes": "Good, slow bolting", "growing_notes": "", "availability": "Specialty Japanese seed suppliers", "sort_order": 9}, {"name": "11. Long White Icicle", "slug": "11-long-white-icicle", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Europe/North America", "traits": "White tapered 12-15cm, narrow", "flesh_fruit": "Tender, mild", "yield_notes": "Quick, 27-35 days", "growi