UPDATE public.garden_import_queue SET payload = '{"species": "Date Palm", "species_slug": "date-palm", "varieties": [{"name": "Barhee (Barhi) 🏆", "slug": "barhee-barhi", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Basra region, Iraq (ancient cultivation, 1000+ years)", "traits": "Medium-height palm (5-10m), heavy trunk with broad leaf bases, long and wide fruit stalks. Named after ''barh'' meaning ''hot wind'' in Arabic.", "flesh_fruit": "Thick, soft, extremely sweet with honey-like, butterscotch, and caramel flavor. Often called ''Honey Dates'' or ''Honey Balls''. Some consider it the sweetest of all date varieties.", "yield_notes": "High-yielding: 6-20 bunches per tree, each bunch 8-15kg. Can produce 80-125kg per mature tree annually.", "growing_notes": "", "availability": "Available from Australian date palm nurseries including Gurra Downs (www.gurradowns.com.au), Daley''s Fruit Tree Nursery, and tissue culture suppliers in Queensland. Widely planted in commercial date farms across Australia.", "sort_order": 0}, {"name": "Medjool (Medjul) 🏆", "slug": "medjool-medjul", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Bou Denib Oasis, Morocco (ancient variety). Only 11 offshoots imported to USA in 1927 to escape Bayoud disease, forming basis of all modern Medjool cultivation outside Morocco.", "traits": "Medium to large palm (up to 20-25m), thick canopy with dense silvery-green to dark green foliage. Wide leaflets create lush, full appearance. Fronds 9-15 feet long. Genetic analysis shows natural hybrid between Phoenix dactylifera and Phoenix theophrasti.", "flesh_fruit": "Very soft, fleshy, moist, sticky texture. Rich, intensely sweet with caramel and honey notes. Premium dessert quality.", "yield_notes": "Moderate to high: 75-100kg per mature tree. Consistent producer.", "growing_notes": "", "availability": "", "sort_order": 1}, {"name": "Deglet Noor (Deglet Nur) 🏆", "slug": "deglet-noor-deglet-nur", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Algerian Sahara near Touggourt, Algeria (1600s). Name means ''Date of Light'' in Arabic. Imported to California 1900, introduced to Australia late 1800s-early 1900s.", "traits": "Medium to tall (12-25m), loose crown with fewer fronds than Medjool, creating open, airy canopy. Silvery blue-green leaves up to 4.5m long. More sparse appearance. Like Medjool, genetic analysis shows natural hybrid with Phoenix theophrasti.", "flesh_fruit": "Firm, chewy texture with delicate, mild honey-like sweetness. Dryer and less sweet than Medjool. Excellent for cooking, baking, and chopping due to firmer texture.", "yield_notes": "High-yielding: 90-135kg (200-300 lbs) per mature tree in ideal conditions.", "growing_notes": "", "availability": "", "sort_order": 2}, {"name": "Zahidi (Zahdi, Zehedi) 🏆", "slug": "zahidi-zahdi-zehedi", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Ancient Mesopotamia/Iraq (thousands of years old). Name derived from Persian ''Azadi'' meaning ''nobility''. Introduced to California around 1900. One of the oldest known cultivars.", "traits": "Stout, fast-growing palm with silvery-green foliage. Slightly larger trunk than Medjool. Dense, full canopy. Short, stiff leaves. Vigorous growth.", "flesh_fruit": "Semi-dry when fresh, very sugary with mild sweetness and slight nutty, peanut butter-like taste. Firm, chewy texture. Less sweet than Medjool or Barhee but excellent flavor. Often used in cooking.", "yield_notes": "Very high productivity. Can produce up to 136kg per tree per season. Heavy bearer. One of the most prolific varieties.", "growing_notes": "", "availability": "Available from specialist date palm nurseries. More commonly grown in Central Australia and drier regions where it performs better.", "sort_order": 3}, {"name": "Halawi (Halawy, Holwah) 🏆", "slug": "halawi-halawy-holwah", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Iraq (ancient variety, name means ''sweet'' in Arabic). One of original varieties brought from Middle East to California. Thousands of years of cultivation history.", "traits": "Even larger palm than Medjool - can reach 20m+ height. Vigorous growth habit. Dense foliage.", "flesh_fruit": "Soft, delicate, tender flesh with extremely sweet caramel or honey-like flavor. Rich, almost melting texture. Often described as having chocolate/fig-like sweetness.", "yield_notes": "Moderate: 60-80kg per mature tree.", "growing_notes": "", "availability": "", "sort_order": 4}, {"name": "Hayani (Hayany) 🏆", "slug": "hayani-hayany", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Egypt (ancient variety, name is a man''s name in Arabic). Most extensively planted cultivar in Egypt. Introduced to California 1901.", "traits": "One of the most cold-tolerant date palms. Medium-sized tree with good vigor.", "flesh_fruit": "Soft, meaty flesh with mild, sweet flavor. Best consumed fresh as it is not easy to cure/dry.", "yield_notes": "Moderate to good productivity. Available year-round in Egypt.", "growing_notes": "", "availability": "", "sort_order": 5}, {"name": "Khadrawy (Khadrawi) 🏆", "slug": "khadrawy-khadrawi", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Basra, Iraq (ancient cultivation). Introduced to USA early 1900s. Thousands of years of cultivation history.", "traits": "Medium-sized palm with characteristic mahogany-colored appearance.", "flesh_fruit": "Soft, meaty flesh with sweet, distinctive chocolate/fig-like, caramel flavor. Rich sweetness. High moisture content.", "yield_notes": "Moderate: 60-80kg per tree.", "growing_notes": "", "availability": "", "sort_order": 6}, {"name": "Dayri 🏆", "slug": "dayri", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Basra, Iraq (ancient variety). Semi-dry type. Naturalized to California and other regions.", "traits": "Medium to large palm, vigorous growth.", "flesh_fruit": "Thick, soft flesh with sweet, unique slightly savory undertone. Rich flavor profile. High fiber content.", "yield_notes": "Moderate to good productivity.", "growing_notes": "", "availability": "", "sort_order": 7}, {"name": "Thoory (Thuri) 🏆", "slug": "thoory-thuri", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Algeria (ancient cultivation). Known as ''Bread Date'' due to dry texture. Traditional variety.", "traits": "Stout palm with short, stiff leaves. Heavy bearing habit. Very large clusters.", "flesh_fruit": "Dry type - sometimes hard and brittle but good, sweet, nutty flavor. Firm, chewy texture. Not sticky. Can be carried in pocket - traditional nomadic food.", "yield_notes": "Very high - heavy bearing variety with very large clusters.", "growing_notes": "", "availability": "Uncommon in Australia. May be available through specialist importers or propagated on special order.", "sort_order": 8}, {"name": "Sayer (Sair, Shamran) 🏆", "slug": "sayer-sair-shamran", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Iran/Middle East, particularly Khuzestan and Bushehr regions. Very old variety, widely cultivated.", "traits": "Large, vigorous palm. One of the major commercial varieties in Iran.", "flesh_fruit": "Soft, semi-dry texture with rich caramel-like flavor and hint of nuttiness. Sweet but not overly cloying. Easy to pit.", "yield_notes": "Good to high productivity.", "growing_notes": "", "availability": "", "sort_order": 9}, {"name": "Khastawi (Khusatawi) 🏆", "slug": "khastawi-khusatawi", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Iraq (leading soft date variety in Iraq). Ancient cultivation.", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "", "sort_order": 10}, {"name": "Barhee (Barhi) 🏆 🌱", "slug": "barhee-barhi", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Basra, Iraq (ancient). Now extensively cultivated in India, particularly Andhra Pradesh, Gujarat, Rajasthan, Tamil Nadu, and increasingly in Kerala.", "traits": "Medium-height (5-10m), heavy trunk, broad leaf bases. Thrives in Mediterranean, desert, subtropical, and tropical climates.", "flesh_fruit": "Thick, extremely sweet with honey, butterscotch, caramel flavors. Sweetest variety. ''Honey Balls'' or ''Honey Dates''.", "yield_notes": "Very high: 6-20 bunches/tree, 8-15kg/bunch. Total 80-125kg annually per mature tree. Developed by ICAR in India in 2016.", "growing_notes": "", "availability": "", "sort_order": 0}, {"name": "Medjool (Medjul) 🏆", "slug": "medjool-medjul", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Morocco. Now cultivated in limited quantities in India (Rajasthan, Gujarat, parts of Tamil Nadu).", "traits": "Large palm (20-25m), dense silvery-green foliage, thick canopy. Hardy in subtropical/tropical zones 9-11.", "flesh_fruit": "Very soft, moist, sticky with rich caramel-honey flavor. Premium quality.", "yield_notes": "75-100kg per mature tree. Good consistency.", "growing_notes": "", "availability": "", "sort_order": 1}, {"name": "Halawi (Halawy) 🏆", "slug": "halawi-halawy", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Iraq (ancient, name means ''sweet'' in Arabic). One of oldest varieties imported to USA. Grown in India.", "traits": "Very large palm (20m+), vigorous, dense foliage.", "flesh_fruit": "Soft, delicate, melting texture with extremely sweet caramel-honey flavor. Rich, almost chocolate/fig notes.", "yield_notes": "60-80kg per tree. Listed in Indian cultivation guides.", "growing_notes": "", "availability": "", "sort_order": 2}, {"name": "Khunezi (Khuneji) 🌱", "slug": "khunezi-khuneji", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Middle East. Cultivated in India, particularly Rajasthan and other date-growing states. Early maturing variety.", "traits": "Medium-sized palm, adapted to Indian growing conditions.", "flesh_fruit": "Deliciously intensely sweet. High quality fruit.", "yield_notes": "Average 40kg per tree (moderate).", "growing_notes": "", "availability": "Available from Indian nurseries, particularly in Rajasthan date palm programs. Agricultural universities in Gujarat and Rajasthan supply this variety.", "sort_order": 3}, {"name": "Khalas 🌱", "slug": "khalas", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Saudi Arabia (Al-Ahsa/Huffuf region - famous cultivation area). Name means ''quintessence'' in Arabic. Now grown in India.", "traits": "Medium-sized palm, cultivated in Rajasthan and other Indian date-growing states.", "flesh_fruit": "Soft, moist, sticky with hearty butter-caramel taste. Medium sweetness level - not too high, not too low, suits most people. Rich, toffee-like flavor.", "yield_notes": "Good productivity. Premium cultivar with mid-season ripening.", "growing_notes": "", "availability": "Available from Indian date palm nurseries in Rajasthan, Gujarat. Listed in Indian agricultural programs.", "sort_order": 4}, {"name": "Khadrawy (Khadrawi) 🏆 🌱", "slug": "khadrawy-khadrawi", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Iraq (ancient). Listed in Indian cultivation as ''Khadarawy''. Grown in Indian date programs.", "traits": "Medium palm, adapted to Indian growing conditions.", "flesh_fruit": "Soft, yellow flesh, sweet with chocolate/fig-like caramel notes. High moisture content.", "yield_notes": "60-80kg per tree. Listed for ''Chaharamaking'' processing.", "growing_notes": "", "availability": "", "sort_order": 5}, {"name": "Zahidi (Zahdi) 🏆 🌱", "slug": "zahidi-zahdi", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Ancient Mesopotamia/Iraq. Extensively cultivated in India (Rajasthan, Gujarat, other states). Listed as ''Wild date palm'' in some Indian references.", "traits": "Stout, fast-growing with silvery-green foliage. Successfully grown throughout India.", "flesh_fruit": "Semi-dry, very sugary, mild sweetness with nutty/peanut butter notes. Firm, chewy.", "yield_notes": "Very high - up to 136kg per tree. Heavy bearer.", "growing_notes": "", "availability": "", "sort_order": 6}, {"name": "Shamran (Sayer) 🏆 🌱", "slug": "shamran-sayer", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Iran/Middle East. Listed in Indian cultivation guides as one of recommended varieties. Widely grown in Persian Gulf countries.", "traits": "Large, vigorous palm. Major commercial variety.", "flesh_fruit": "Soft, semi-dry with rich caramel flavor and nutty hints. Heavy, sweet.", "yield_notes": "Good to high productivity.", "growing_notes": "", "availability": "", "sort_order": 7}, {"name": "Khastawi 🏆 🌱", "slug": "khastawi", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Iraq - leading soft date in Iraq. Ancient cultivation. Grown in India.", "traits": "Large, vigorous palm adapted to desert conditions but with humidity tolerance.", "flesh_fruit": "Syrupy, extremely sweet. Prized for dessert.", "yield_notes": "Good productivity.", "growing_notes": "", "availability": "", "sort_order": 8}, {"name": "Dayri 🏆 🌱", "slug": "dayri", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Basra, Iraq. Listed in Indian agricultural guides as semi-dry variety suitable for cultivation.", "traits": "Medium-large palm, vigorous growth.", "flesh_fruit": "Thick, soft with sweet, slightly savory flavor. High fiber content.", "yield_notes": "Moderate to good productivity.", "growing_notes": "", "availability": "", "sort_order": 9}, {"name": "Thoory 🏆 🌱", "slug": "thoory", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Algeria. ''Bread Date''. Listed in Indian cultivation guides as dry variety.", "traits": "Stout with short stiff leaves, heavy bearing, very large clusters.", "flesh_fruit": "Dry, sometimes hard but good sweet nutty flavor. Not sticky.", "yield_notes": "Very high with very large clusters.", "growing_notes": "", "availability": "", "sort_order": 10}, {"name": "Ajwa (Ajwah) 🏆", "slug": "ajwa-ajwah", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Al-Madinah region, Saudi Arabia. Considered holy fruit in Islamic tradition with spiritual significance.", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "", "sort_order": 11}, {"name": "Safawi", "slug": "safawi", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Madinah, Saudi Arabia. Productive variety available year-round.", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "", "sort_order": 12}, {"name": "Phoenix sylvestris (Indian Wild Date Palm) 🏆", "slug": "phoenix-sylvestris-indian-wild-date-palm", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Native to India - found throughout most of India including Kerala region.", "traits": "Indigenous Indian palm species, smaller fruit than Phoenix dactylifera.", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "", "sort_order": 13}], "variety_count": 25}'::jsonb,
