UPDATE public.garden_import_queue SET payload = '{"species": "Fringe Tree", "species_slug": "fringe-tree", "varieties": [{"name": "Chionanthus retusus (Chinese Fringe Tree)", "slug": "chionanthus-retusus-chinese-fringe-tree", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Vegetative propagation from 10m specimen at Arnold Arboretum, original seed from Imperial Botanic Gardens Tokyo (1901)", "traits": "Vase-shaped crown, single trunk form, impressive mature size potential", "flesh_fruit": "", "yield_notes": "", "growing_notes": "Air pollution tolerant, adapts well to urban settings. Prefers deep moist fertile acidic soils but adaptable. Flowers on current year''s growth. Available widely in Australian nurseries.", "availability": "Shadow Nursery, specialty tree nurseries", "sort_order": 0}, {"name": "Chionanthus virginicus (White Fringe Tree)", "slug": "chionanthus-virginicus-white-fringe-tree", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Selected by Dr. Michael Dirr, Georgia before 2019", "traits": "Vigorous tree-forming clone, fastest grower in nursery production; male; dark green leaves larger than other cultivars", "flesh_fruit": "", "yield_notes": "", "growing_notes": "Air pollution tolerant, adapts to varied soils (clay, sand, loam). Slow growing (6-10 inches/year). Native Americans used bark for medicinal purposes. Related to lilac, privet, forsythia, jasmine, ash, olive.", "availability": "US specialty nurseries, can be imported", "sort_order": 1}, {"name": "Chionanthus axillaris (Native Olive/Pimply Olive)", "slug": "chionanthus-axillaris-native-olive-pimply-olive", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "origin": "Native to North Queensland, Australia - INDIGENOUS to Australia", "traits": "Evergreen tree to 30 m tall, 40 cm dbh; white/pale brown twigs 1 mm diameter with small lenticels", "flesh_fruit": "", "yield_notes": "", "growing_notes": "Conservation status: Least Concern. Native species supporting local ecosystem and wildlife. Evergreen providing year-round foliage.", "availability": "Queensland native plant nurseries, rainforest plant specialists", "sort_order": 2}, {"name": "Chionanthus ramiflorus (Native Olive)", "slug": "chionanthus-ramiflorus-native-olive", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Tropical and subtropical Asia to North Queensland - found in Queensland", "traits": "Evergreen tree/shrub, 3-23 m tall; quadrangular young branchlets becoming terete when mature", "flesh_fruit": "", "yield_notes": "", "growing_notes": "Less prolific in flower than C. retusus or C. virginicus but adapted to local conditions. Evergreen habit.", "availability": "Australian rainforest plant nurseries", "sort_order": 3}, {"name": "Chionanthus pygmaeus (Pygmy Fringe Tree)", "slug": "chionanthus-pygmaeus-pygmy-fringe-tree", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Endemic to Central Florida, USA - rare and endangered", "traits": "Deciduous shrub, 2-8 ft (0.6-2.4 m) tall, rarely to 4 m; smaller than C. virginicus", "flesh_fruit": "", "yield_notes": "", "growing_notes": "Federally endangered species in USA. Extremely rare in cultivation. Grows in Florida scrub on deep sandy soils. Dwarf habit ideal for small gardens. Sometimes hybridizes with C. virginicus.", "availability": "Very limited - Mr Maple Nursery (North Carolina only), few specialty collections. Import restrictions may apply.", "sort_order": 4}, {"name": "Chionanthus zeylanicus 🌏", "slug": "chionanthus-zeylanicus", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "INDIGENOUS to South India and Sri Lanka - found in Western Ghats-South Sahyadri region including Kerala", "traits": "Evergreen tree up to 10 m tall; greyish scaly bark with cream blaze; terete lenticellate branchlets", "flesh_fruit": "", "yield_notes": "", "growing_notes": "Evergreen habit maintains year-round foliage in tropical climate. Synonyms include Linociera zeylanica.", "availability": "Kerala Forest Research Institute, Kerala native plant nurseries, Western Ghats biodiversity nurseries", "sort_order": 0}, {"name": "Chionanthus mala-elengi 🌏", "slug": "chionanthus-mala-elengi", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Indian subcontinent", "traits": "Tree growing in seasonally dry tropical biome", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Kerala Forest Research Institute, Indian native plant nurseries, botanical gardens", "sort_order": 1}, {"name": "Chionanthus ramiflorus 🌏", "slug": "chionanthus-ramiflorus", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Peninsular India variant", "traits": "Evergreen tree up to 20 m tall; greyish brown corky lenticellate bark; quadrangular young branchlets", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Kerala Forest Research Institute (Peechi), forest nurseries, biodiversity conservation programs", "sort_order": 2}, {"name": "Chionanthus courtallensis 🌏", "slug": "chionanthus-courtallensis", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "India (Courtallam region in Tamil Nadu, near Kerala border)", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "Regional species from nearby Western Ghats area. Likely found in border regions between Tamil Nadu and Kerala.", "availability": "Western Ghats plant specialists, Tamil Nadu/Kerala forest nurseries", "sort_order": 3}, {"name": "Chionanthus retusus (Chinese Fringe Tree)", "slug": "chionanthus-retusus-chinese-fringe-tree", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Eastern Asia (China, Japan, Korea, Taiwan)", "traits": "Deciduous tree/shrub 10-20 ft tall (up to 30-40 ft); exfoliating bark; white fragrant flowers", "flesh_fruit": "", "yield_notes": "", "growing_notes": "Can